import React, { useCallback, useRef, useState } from 'react';

export const PayrollUploadPanel = ({ t, isUploading, onDownloadTemplate, onFileUpload }) => {
  const inputRef = useRef(null);
  const [isDragActive, setIsDragActive] = useState(false);

  const resetInput = useCallback(() => {
    if (inputRef.current) {
      inputRef.current.value = '';
    }
  }, []);

  const handleFileSelection = useCallback(
    (fileList) => {
      const file = fileList?.[0];
      if (!file) {return;}
      onFileUpload(file);
      resetInput();
    },
    [onFileUpload, resetInput]
  );

  const handleInputChange = useCallback(
    (event) => {
      handleFileSelection(event.target.files);
    },
    [handleFileSelection]
  );

  const handleDrop = useCallback(
    (event) => {
      event.preventDefault();
      event.stopPropagation();
      setIsDragActive(false);
      handleFileSelection(event.dataTransfer.files);
    },
    [handleFileSelection]
  );

  const handleDragOver = useCallback((event) => {
    event.preventDefault();
    event.stopPropagation();
  }, []);

  const handleDragEnter = useCallback((event) => {
    event.preventDefault();
    event.stopPropagation();
    setIsDragActive(true);
  }, []);

  const handleDragLeave = useCallback((event) => {
    event.preventDefault();
    event.stopPropagation();
    setIsDragActive(false);
  }, []);

  const handleSelectClick = useCallback(() => {
    if (!isUploading) {
      inputRef.current?.click();
    }
  }, [isUploading]);

  return (
    <div>
      {/* Section Header */}
      <div className="payroll-section-header">
        <h2 className="payroll-section-title">
          {t('uploadPayrollFile', { ns: 'payroll' })}
        </h2>
        <p className="payroll-section-description">
          {t('uploadCsvOrExcel', { ns: 'payroll' })}
        </p>
      </div>

      {/* Download Template Button */}
      <div style={{ marginBottom: '32px', textAlign: 'center' }}>
        <button
          className="payroll-btn payroll-btn--secondary"
          data-tour="payroll-download"
          onClick={onDownloadTemplate}
        >
          <span className="material-symbols-outlined" style={{ fontSize: '18px' }}>
            download
          </span>
          {t('downloadCsvTemplate', { ns: 'payroll' })}
        </button>
      </div>

      {/* Upload Area */}
      <div
        role="presentation"
        data-tour="payroll-upload"
        onDrop={handleDrop}
        onDragOver={handleDragOver}
        onDragEnter={handleDragEnter}
        onDragLeave={handleDragLeave}
        className={`payroll-upload-area ${isDragActive ? 'drag-active' : ''}`}
      >
        <input
          ref={inputRef}
          type="file"
          accept="text/csv,application/vnd.ms-excel,application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
          onChange={handleInputChange}
          style={{ display: 'none' }}
          disabled={isUploading}
          multiple={false}
        />
        <button
          type="button"
          onClick={handleSelectClick}
          style={{
            background: 'none',
            border: 'none',
            padding: 0,
            margin: 0,
            width: '100%',
            cursor: isUploading ? 'not-allowed' : 'pointer',
          }}
        >
          <span className="payroll-upload-icon material-symbols-outlined">
            cloud_upload
          </span>
          <p className="payroll-upload-title">
            {isUploading ? t('uploading', { ns: 'payroll' }) : t('clickToUpload', { ns: 'payroll' })}
          </p>
          <p className="payroll-upload-description">
            {t('onlyCsvFiles', { ns: 'payroll' })}
          </p>
          <button
            className="payroll-btn payroll-btn--primary"
            disabled={isUploading}
            style={{ marginTop: '16px' }}
          >
            {isUploading ? t('uploading', { ns: 'payroll' }) : t('selectFile', { ns: 'payroll' })}
          </button>
        </button>
      </div>

      {/* Requirements Card */}
      <div
        data-tour="payroll-requirements"
        className="payroll-requirements-card"
      >
        <div className="payroll-requirements-header">
          <span className="material-symbols-outlined">playlist_add_check</span>
          {t('fileFormatRequirements', { ns: 'payroll' })}
        </div>
        <p className="payroll-requirements-text">
          Download the template or ensure your sheet uses the exact header names below. Reference numbers are automatically generated for each employee.
        </p>
        
        <div className="payroll-requirements-section">
          <div className="payroll-requirements-title">Required columns:</div>
          <p className="payroll-requirements-text">
            First Name, Last Name, Position, Amount, Email, Currency, Phone, Payment Channel
          </p>
        </div>

        <div className="payroll-requirements-section">
          <div className="payroll-requirements-title">Optional columns:</div>
          <p className="payroll-requirements-text">
            Network, Mobile Number, Bank Name, Bank Account No, Bank Branch
          </p>
          <p className="payroll-requirements-text" style={{ fontStyle: 'italic', marginTop: '4px' }}>
            Use Mobile Number when Payment Channel is MOBILE_MONEY. Use Bank fields when Payment Channel is BANK.
          </p>
        </div>

        <div className="payroll-requirements-tip">
          <div className="payroll-requirements-tip-title">Tips:</div>
          <ul className="payroll-requirements-list">
            <li>Payment Channel accepts <strong>MOBILE_MONEY</strong> or <strong>BANK</strong></li>
            <li>For MOBILE_MONEY: include Network (MTN, TELECEL, or AIRTEL-TIGO) and Mobile Number</li>
            <li>For BANK: include Bank Name, Bank Account No, and Bank Branch</li>
            <li>Amount should be numeric only (no currency symbols)</li>
            <li>Reference is auto-generated - no need to include it in your CSV</li>
          </ul>
        </div>

        <div className="payroll-requirements-tip">
          <div className="payroll-requirements-tip-title">Sample row:</div>
          <p className="payroll-requirements-text" style={{ fontFamily: 'monospace', wordBreak: 'break-all' }}>
            Eius,Boxing,HR Officer,180,eius.hosteng@example.com,EUR,233504567890,MOBILE_MONEY,MTN,233504567890
          </p>
        </div>
      </div>
    </div>
  );
};

