import { useCallback, useEffect, useMemo, useState } from 'react';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { apiRequest } from '@/shared/services/apiClient.js';
import { tokenService } from '@/features/auth/services/tokenService.js';
import { API_CONFIG } from '@/app/config/apiConfig.js';
import { useMutation } from '@/shared/hooks';
import { queryKeys } from '@/shared/utils/queryKeys.js';
import { generateReference, validateReference } from '@/features/disbursements/utils/helpers.js';
import { useDisbursementServices } from '@/features/disbursements/hooks/useDisbursementServices.js';
import { parseCSVPayroll, parseExcelPayroll } from '@/features/payroll/utils/parsePayrollCSV.js';

// Use tokenService helper to resolve the correct header user id (business-aware)

const ITEMS_PER_PAGE = 10;

export const usePayrollProcessing = ({ t }) => {
  const { success, info, error } = useToast();

  // Determine if user is business account
  const isBusiness = useMemo(() => {
    try {
      const userData = JSON.parse(localStorage.getItem('userData') || '{}');
      return userData?.usertype?.toLowerCase() === 'business_contact';
    } catch {
      return false;
    }
  }, []);

  // Use the same service ID fetching as single disbursement
  const { disbursementServiceId } = useDisbursementServices();

  const [windowWidth, setWindowWidth] = useState(typeof window !== 'undefined' ? window.innerWidth : 0);
  const [isUploading, setIsUploading] = useState(false);
  const [filePreview, setFilePreview] = useState(null);
  const [employeesFromFile, setEmployeesFromFile] = useState([]);
  const [currentPage, setCurrentPage] = useState(1);

  // Use React Query mutation for payroll processing
  const processPayrollMutation = useMutation({
    mutationFn: async ({ payrollRecords, headers }) => {
      return await apiRequest('/v1/employee-payments/process', {
        method: 'POST',
        baseUrl: API_CONFIG.DISBURSEMENT_BASE_URL,
        headers,
        body: JSON.stringify(payrollRecords),
      });
    },
    invalidateQueries: [
      queryKeys.payroll.all(),
      queryKeys.dashboard.all(),
      queryKeys.wallet.balance(),
      queryKeys.reports.all(),
    ],
    onSuccess: () => {
      success(
        t('payrollProcessedSuccess', {
          ns: 'payroll',
          count: validEmployees.length,
          amount: totalAmount.toLocaleString(),
        })
      );
      setFilePreview(null);
      setEmployeesFromFile([]);
    },
    onError: (err) => {
      // Handle insufficient balance specifically (code 07)
      if (err?.code === '07' || (err?.message && err.message.toLowerCase().includes('insufficient'))) {
        error('insufficient balance');
      } else {
        error(t('failedToProcessPayroll', { ns: 'payroll', error: err.message }));
      }
    },
  });

  useEffect(() => {
    let resizeTimer = null;
    const handleResize = () => {
      // Debounce resize events to prevent excessive re-renders
      if (resizeTimer) {
        clearTimeout(resizeTimer);
      }
      resizeTimer = setTimeout(() => {
        setWindowWidth(window.innerWidth);
      }, 100);
    };

    window.addEventListener('resize', handleResize);
    return () => {
      window.removeEventListener('resize', handleResize);
      if (resizeTimer) {
        clearTimeout(resizeTimer);
      }
    };
  }, []);

  useEffect(() => {
    setCurrentPage(1);
  }, [employeesFromFile]);

  const totalPages = Math.max(1, Math.ceil(employeesFromFile.length / ITEMS_PER_PAGE));
  const currentEmployees = useMemo(() => {
    const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
    const endIndex = startIndex + ITEMS_PER_PAGE;
    return employeesFromFile.slice(startIndex, endIndex);
  }, [currentPage, employeesFromFile]);

  const validEmployees = useMemo(
    () => employeesFromFile.filter((emp) => !Number.isNaN(emp.amount) && emp.amount > 0),
    [employeesFromFile]
  );

  const totalAmount = useMemo(
    () => validEmployees.reduce((sum, emp) => sum + emp.amount, 0),
    [validEmployees]
  );

  const parseEmployeesFromFile = useCallback(
    async (file) => {
      let parsedEmployees;

      if (file.name.match(/\.(xlsx|xls)$/i)) {
        // Parse Excel file
        const buffer = await file.arrayBuffer();
        parsedEmployees = parseExcelPayroll(buffer, t);
      } else {
        // Parse CSV file
        const text = await file.text();
        parsedEmployees = parseCSVPayroll(text, t);
      }

      setEmployeesFromFile(parsedEmployees);
      setFilePreview({
        filename: file.name,
        size: `${(file.size / 1024).toFixed(2)} KB`,
        rows: parsedEmployees.length + 1, // +1 for header
        employees: parsedEmployees.length,
        headers: Object.keys(parsedEmployees[0] || {}),
      });

      success(t('fileUploadedParsed', { ns: 'payroll', count: parsedEmployees.length }));
    },
    [success, t]
  );

  const handleFileUpload = useCallback(
    async (file) => {
      if (!file) { return; }

      const allowedTypes = [
        'text/csv',
        'application/vnd.ms-excel',
        'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      ];

      if (!allowedTypes.includes(file.type)) {
        error(`${t('uploadValidFile', { ns: 'payroll' })} (${file.type})`);
        return;
      }

      setIsUploading(true);

      try {
        await new Promise((resolve) => setTimeout(resolve, 500));
        await parseEmployeesFromFile(file);
      } catch (err) {
        error(t('failedToProcessFile', { ns: 'payroll', error: err.message }));
        setFilePreview(null);
        setEmployeesFromFile([]);
      } finally {
        setIsUploading(false);
      }
    },
    [error, parseEmployeesFromFile, t]
  );

  const handleApprovePayroll = useCallback(async () => {
    if (!filePreview) {
      error(t('pleaseUploadFile', { ns: 'payroll' }));
      return;
    }

    // Build payroll payload as an array of objects matching the exact API format
    const payrollRecords = validEmployees.map(emp => {
      const { id, name, salary, status, ...record } = emp;

      // Ensure the payload matches the exact structure required by the API
      // Structure must match: [{ firstName, lastName, position, reference, amount (number), email, currency, phone, paymentChannel, network, momoNumber, bankName, bankAccountNo, bankBranch, source }]
      const payrollRecord = {
        firstName: String(record.firstName || '').trim(),
        lastName: String(record.lastName || '').trim(),
        position: String(record.position || '').trim(),
        reference: String(record.reference || '').trim(),
        amount: parseFloat(record.amount) || 0, // Must be a number, not string (e.g., 500.00, 750.50)
        email: String(record.email || '').trim(),
        currency: String(record.currency || '').trim().toUpperCase(),
        phone: String(record.phone || '').trim(),
        paymentChannel: String(record.paymentChannel || '').trim(),
        network: record.network ? String(record.network).trim() : null,
        momoNumber: record.mobileNumber ? String(record.mobileNumber).trim() : null,
        bankName: record.bankName ? String(record.bankName).trim() : null,
        bankAccountNo: record.bankAccountNo ? String(record.bankAccountNo).trim() : null,
        bankBranch: record.bankBranch ? String(record.bankBranch).trim() : null,
        source: 'dashboard', // Add source to track origin of payroll
      };

      return payrollRecord;
    });

    if (!Array.isArray(payrollRecords)) {
      error('Payroll records must be an array');
      return;
    }

    // Transaction limit validation removed - users can now process payroll without verification level restrictions

    if (tokenService.isAuthenticated()) {
      const userId = tokenService.getHeaderUserId?.() || null;
      const headers = {};

      if (userId) {
        // Use x-user-id header (business-aware)
        headers['x-user-id'] = String(userId);
      } else {
        error('User ID not found. Please log in again.');
        return;
      }

      // Add service-id header (same as single disbursement)
      if (disbursementServiceId) {
        headers['service-id'] = String(disbursementServiceId);
      }

      // Use mutation to process payroll
      processPayrollMutation.mutate({ payrollRecords, headers });
    } else {
      // Fallback for non-authenticated (shouldn't happen in production)
      await new Promise((resolve) => setTimeout(resolve, 2000));
      success(
        t('payrollProcessedSuccess', {
          ns: 'payroll',
          count: validEmployees.length,
          amount: totalAmount.toLocaleString(),
        })
      );
      setFilePreview(null);
      setEmployeesFromFile([]);
    }
  }, [error, filePreview, success, t, totalAmount, validEmployees, processPayrollMutation]);

  const handleDownloadTemplate = useCallback(() => {
    // Template headers matching the exact payload structure and order
    // Reference is auto-generated (not included in template)
    // Order: firstName, lastName, position, amount, email, currency, phone, paymentChannel, network, momoNumber, bankName, bankAccountNo, bankBranch
    const headers = [
      'First Name',
      'Last Name',
      'Position',
      'Amount',
      'Email',
      'Currency',
      'Phone',
      'Payment Channel',
      'Network', // Optional - required for MOBILE_MONEY
      'Momo Number', // Optional - required for MOBILE_MONEY (maps to momoNumber in payload)
      'Bank Name', // Optional - required for BANK
      'Bank Account No', // Optional - required for BANK
      'Bank Branch' // Optional - required for BANK
    ];

    // Sample data rows with proper formatting
    const sampleRows = [
      ['John', 'Doe', 'Manager', '1500.00', 'john.doe@example.com', 'GHS', '="233241234567"', 'MOBILE_MONEY', 'MTN', '="233241234567"', '', '', ''],
      ['Jane', 'Smith', 'Developer', '2000.00', 'jane.smith@example.com', 'GHS', '="233201234567"', 'MOBILE_MONEY', 'TELECEL', '="233201234567"', '', '', ''],
      ['Robert', 'Brown', 'Accountant', '1800.00', 'robert.brown@example.com', 'GHS', '="233501234567"', 'BANK', '', '', 'Standard Chartered', '="1234567890"', 'Accra Main']
    ];

    // Helper function to escape CSV values
    const escapeCsvValue = (value) => {
      if (value === null || value === undefined || value === '') { return ''; }
      const stringValue = String(value);
      // If value contains comma, quote, or newline, wrap in quotes and escape quotes
      if (stringValue.includes(',') || stringValue.includes('"') || stringValue.includes('\n')) {
        return `"${stringValue.replace(/"/g, '""')}"`;
      }
      return stringValue;
    };

    // Build CSV content with headers and sample rows
    const headerRow = headers.map(escapeCsvValue).join(',');
    const dataRows = sampleRows.map(row => row.map(escapeCsvValue).join(',')).join('\n');
    const csvContent = headerRow + '\n' + dataRows;

    // Add BOM for Excel compatibility
    const BOM = '\uFEFF';
    const blob = new Blob([BOM + csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = window.URL.createObjectURL(blob);
    const anchor = document.createElement('a');
    anchor.href = url;
    anchor.download = 'payroll_template.csv';
    // Position the link off-screen to prevent visual issues
    anchor.style.position = 'absolute';
    anchor.style.left = '-9999px';
    anchor.style.top = '-9999px';
    anchor.style.opacity = '0';
    anchor.style.visibility = 'hidden';
    anchor.style.pointerEvents = 'none';
    document.body.appendChild(anchor);
    anchor.click();
    // Clean up after a short delay
    setTimeout(() => {
      document.body.removeChild(anchor);
      window.URL.revokeObjectURL(url);
    }, 100);

    info(t('csvTemplateDownloaded', { ns: 'payroll' }));
  }, [info, t]);

  const handleCancelUpload = useCallback(() => {
    setFilePreview(null);
    setEmployeesFromFile([]);
  }, []);

  const handlePageChange = useCallback(
    (page) => {
      if (page < 1 || page > totalPages) { return; }
      setCurrentPage(page);
    },
    [totalPages]
  );

  return {
    windowWidth,
    isUploading,
    isProcessing: processPayrollMutation.isPending,
    filePreview,
    employeesFromFile,
    currentEmployees,
    currentPage,
    totalPages,
    totalAmount,
    validEmployeesCount: validEmployees.length,
    handleFileUpload,
    handleApprovePayroll,
    handleDownloadTemplate,
    handleCancelUpload,
    handlePageChange,
  };
};

