import React from 'react';

export const PayrollPreviewPanel = ({
  t,
  filePreview,
  isProcessing,
  employeesFromFile,
  currentEmployees,
  currentPage,
  totalPages,
  totalAmount,
  validEmployeesCount,
  onCancelUpload,
  onApprovePayroll,
  onPageChange,
}) => (
  <div>
    {/* Preview Header */}
    <div className="payroll-preview-header">
      <h2 className="payroll-preview-title">
        {t('filePreviewApproval', { ns: 'payroll' })}
      </h2>
      <div className="payroll-preview-actions">
        <button 
          className="payroll-btn payroll-btn--secondary" 
          onClick={onCancelUpload} 
          disabled={isProcessing}
        >
          {t('cancel', { ns: 'payroll' })}
        </button>
        <button 
          className="payroll-btn payroll-btn--primary" 
          onClick={onApprovePayroll} 
          disabled={isProcessing}
        >
          {isProcessing
            ? t('processing', { ns: 'payroll' })
            : t('approvePayEmployees', { ns: 'payroll', count: validEmployeesCount })}
        </button>
      </div>
    </div>

    {/* Summary Card */}
    <div className="payroll-summary-card" data-tour="payroll-summary">
      <div className="payroll-summary-header">
        <span className="material-symbols-outlined">description</span>
        {filePreview.filename}
      </div>
      <div className="payroll-summary-grid">
        <SummaryItem label={t('fileSize', { ns: 'payroll' })} value={filePreview.size} />
        <SummaryItem label={t('totalRows', { ns: 'payroll' })} value={filePreview.rows} />
        <SummaryItem label={t('employees', { ns: 'payroll' })} value={filePreview.employees} />
        <SummaryItem
          label={t('totalAmount', { ns: 'payroll' })}
          value={
            <span className="payroll-summary-value--accent">
              {employeesFromFile[0]?.currency || 'GHS'} {totalAmount.toLocaleString()}
            </span>
          }
        />
      </div>
    </div>

    {/* Employee Data Preview */}
    <div data-tour="payroll-preview">
      <h3 style={{ marginBottom: '16px', color: 'var(--text-primary)', fontSize: '1.2rem' }}>
        {t('employeeDataPreview', { ns: 'payroll' })}
      </h3>
      <div className="payroll-table-container">
        <table className="payroll-table">
          <thead>
            <tr>
              <th style={{ minWidth: '120px' }}>Reference</th>
              <th style={{ minWidth: '150px' }}>Name</th>
              <th style={{ minWidth: '120px' }}>Position</th>
              <th style={{ minWidth: '200px' }}>Email</th>
              <th style={{ minWidth: '120px' }}>Phone</th>
              <th style={{ minWidth: '100px' }}>Amount</th>
              <th style={{ minWidth: '80px' }}>Currency</th>
              <th style={{ minWidth: '120px' }}>Payment Channel</th>
            </tr>
          </thead>
          <tbody>
            {currentEmployees.map((employee) => (
              <tr key={employee.id}>
                <td style={{ fontSize: '12px', color: 'var(--text-primary)' }}>{employee.reference}</td>
                <td style={{ fontWeight: '600', color: 'var(--text-primary)' }}>
                  {employee.firstName} {employee.lastName}
                </td>
                <td style={{ color: 'var(--text-primary)' }}>{employee.position}</td>
                <td style={{ color: 'var(--text-muted)', fontSize: '12px' }}>{employee.email}</td>
                <td style={{ color: 'var(--text-muted)', fontSize: '12px' }}>{employee.phone}</td>
                <td style={{ fontWeight: '600', color: 'var(--accent)' }}>
                  {employee.amount > 0 ? employee.amount.toLocaleString() : '0'}
                </td>
                <td style={{ color: 'var(--text-muted)' }}>{employee.currency}</td>
                <td style={{ color: 'var(--text-muted)', fontSize: '12px' }}>{employee.paymentChannel}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Pagination */}
      {totalPages > 1 && (
        <div className="payroll-pagination">
          <button
            onClick={() => onPageChange(currentPage - 1)}
            disabled={currentPage === 1}
            className={`payroll-pagination-btn ${
              currentPage === 1 ? 'payroll-pagination-btn--disabled' : 'payroll-pagination-btn--inactive'
            }`}
          >
            {t('previous', { ns: 'common' })}
          </button>

          <div style={{ display: 'flex', gap: '4px', flexWrap: 'wrap' }}>
            {Array.from({ length: totalPages }, (_, index) => index + 1).map((page) => (
              <button
                key={page}
                onClick={() => onPageChange(page)}
                className={`payroll-pagination-btn ${
                  currentPage === page 
                    ? 'payroll-pagination-btn--active' 
                    : 'payroll-pagination-btn--inactive'
                }`}
              >
                {page}
              </button>
            ))}
          </div>

          <button
            onClick={() => onPageChange(currentPage + 1)}
            disabled={currentPage === totalPages}
            className={`payroll-pagination-btn ${
              currentPage === totalPages ? 'payroll-pagination-btn--disabled' : 'payroll-pagination-btn--inactive'
            }`}
          >
            {t('next', { ns: 'common' })}
          </button>

          <div className="payroll-pagination-info">
            {t('pageOf', { ns: 'common', current: currentPage, total: totalPages })} •{' '}
            {employeesFromFile.length} {t('totalEmployees', { ns: 'payroll' })}
          </div>
        </div>
      )}
    </div>
  </div>
);

const SummaryItem = ({ label, value }) => (
  <div className="payroll-summary-item">
    <div className="payroll-summary-label">{label}</div>
    <div className="payroll-summary-value">{value}</div>
  </div>
);

