import React from 'react';
import { useTranslation } from 'react-i18next';
import { useWindowSize } from '@/shared/hooks/useWindowSize.js';
import { usePayrollProcessing } from './hooks/usePayrollProcessing.js';
import { PayrollUploadPanel } from './components/PayrollUploadPanel.jsx';
import { PayrollPreviewPanel } from './components/PayrollPreviewPanel.jsx';
import { BarChart3, ArrowRight, CreditCard } from 'lucide-react';
import '/styles/index.css';
import '/styles/pages/payroll/index.css';

const PayrollPage = () => {
  const { t } = useTranslation();
  const { width: windowWidth } = useWindowSize();
  const {
    isUploading,
    isProcessing,
    filePreview,
    employeesFromFile,
    currentEmployees,
    currentPage,
    totalPages,
    totalAmount,
    validEmployeesCount,
    handleFileUpload,
    handleApprovePayroll,
    handleDownloadTemplate,
    handleCancelUpload,
    handlePageChange,
  } = usePayrollProcessing({ t });

  return (
    <div className="payroll-page">
      {/* Page Header */}
      <div className="payroll-header" data-tour="payroll-header">
        <div className="payroll-header-content">
          <div className="payroll-header-text">
            <h1 className="payroll-title">
              {t('payrollManagement', { ns: 'payroll' })}
            </h1>
            <p className="payroll-subtitle">
              {t('uploadCsvFiles', { ns: 'payroll' })}
            </p>
          </div>
          <div className="payroll-header-icon">
            <CreditCard size={36} />
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div className="payroll-content">
        <div className="payroll-section">
          {!filePreview ? (
            <PayrollUploadPanel
              t={t}
              isUploading={isUploading}
              onDownloadTemplate={handleDownloadTemplate}
              onFileUpload={handleFileUpload}
            />
          ) : (
            <PayrollPreviewPanel
              t={t}
              filePreview={filePreview}
              isProcessing={isProcessing}
              employeesFromFile={employeesFromFile}
              currentEmployees={currentEmployees}
              currentPage={currentPage}
              totalPages={totalPages}
              totalAmount={totalAmount}
              validEmployeesCount={validEmployeesCount}
              onCancelUpload={handleCancelUpload}
              onApprovePayroll={handleApprovePayroll}
              onPageChange={handlePageChange}
            />
          )}
        </div>

        {/* Payroll History Section */}
        <div className="payroll-section payroll-history-section" data-tour="payroll-history-info">
          <div className="payroll-history-icon">
            <BarChart3 size={48} />
          </div>
          <h3 className="payroll-history-title">
            {t('viewPayrollHistory', { ns: 'payroll', defaultValue: 'View Complete Payroll History' })}
          </h3>
          <p className="payroll-history-description">
            {t('payrollHistoryDescription', { 
              ns: 'payroll', 
              defaultValue: 'For detailed payroll transaction history, filtering by date ranges, and Excel export functionality, please visit the Reports page.' 
            })}
          </p>
          <button
            onClick={() => window.location.href = '/reports'}
            className="payroll-btn payroll-btn--primary"
          >
            {t('goToReports', { ns: 'payroll', defaultValue: 'Go to Reports' })}
            <ArrowRight size={16} />
          </button>
        </div>
      </div>
    </div>
  );
};

export default PayrollPage;

