/**
 * CSV/Excel Parser for Payroll
 * 
 * Parses CSV and Excel files for payroll uploads, validates data,
 * and returns structured records ready for API submission.
 */

import { read, utils } from 'xlsx';
import { generateReference, validateReference } from '@/features/disbursements/utils/helpers.js';
import logger from '@/shared/utils/logger.js';

// Expected headers (case-insensitive mapping with variations)
const HEADER_MAP = {
    'first name': 'firstName',
    'first_name': 'firstName',
    'firstname': 'firstName',
    'fname': 'firstName',
    'last name': 'lastName',
    'last_name': 'lastName',
    'lastname': 'lastName',
    'lname': 'lastName',
    'surname': 'lastName',
    'position': 'position',
    'job title': 'position',
    'job_title': 'position',
    'jobtitle': 'position',
    'amount': 'amount',
    'amt': 'amount',
    'value': 'amount',
    'email': 'email',
    'e-mail': 'email',
    'email address': 'email',
    'email_address': 'email',
    'currency': 'currency',
    'curr': 'currency',
    'phone': 'phone',
    'phone number': 'phone',
    'phone_number': 'phone',
    'phonenumber': 'phone',
    'mobile': 'phone',
    'payment channel': 'paymentChannel',
    'payment_channel': 'paymentChannel',
    'paymentchannel': 'paymentChannel',
    'channel': 'paymentChannel',
    'network': 'network',
    'provider': 'network',
    'mobile number': 'mobileNumber',
    'mobile_number': 'mobileNumber',
    'mobilenumber': 'mobileNumber',
    'momo number': 'mobileNumber',
    'momo_number': 'mobileNumber',
    'momonumber': 'mobileNumber',
    'momo': 'mobileNumber',
    'mobile money number': 'mobileNumber',
    'bank name': 'bankName',
    'bank_name': 'bankName',
    'bankname': 'bankName',
    'bank account no': 'bankAccountNo',
    'bank_account_no': 'bankAccountNo',
    'bank_account_number': 'bankAccountNo',
    'bankaccountno': 'bankAccountNo',
    'account number': 'bankAccountNo',
    'account_number': 'bankAccountNo',
    'bank branch': 'bankBranch',
    'bank_branch': 'bankBranch',
    'bankbranch': 'bankBranch',
    'branch': 'bankBranch'
};

/**
 * Normalize phone number with scientific notation handling
 */
const normalizePhoneNumber = (phoneRaw, rowIndex, fieldName = 'Phone') => {
    if (!phoneRaw) {return '';}

    let phoneStr = phoneRaw.toString().trim();

    // Handle scientific notation
    if (phoneStr.includes('E+') || phoneStr.includes('e+') || phoneStr.includes('E-') || phoneStr.includes('e-')) {
        try {
            const num = parseFloat(phoneStr);
            if (!isNaN(num)) {
                let numStr = num.toString();
                if (numStr.includes('e') || numStr.includes('E')) {
                    try {
                        const rounded = Math.round(num);
                        numStr = BigInt(rounded).toString();
                    } catch {
                        const match = phoneStr.match(/^(\d+\.?\d*)[Ee][+-]?(\d+)$/);
                        if (match) {
                            const baseStr = match[1];
                            const exp = parseInt(match[2]);
                            const [integerPart, decimalPart = ''] = baseStr.split('.');
                            let fullNumber = integerPart + decimalPart;
                            const totalDigitsNeeded = integerPart.length + exp;
                            const currentDigits = fullNumber.length;
                            if (currentDigits < totalDigitsNeeded) {
                                fullNumber = fullNumber.padEnd(totalDigitsNeeded, '0');
                            } else if (currentDigits > totalDigitsNeeded) {
                                fullNumber = fullNumber.substring(0, totalDigitsNeeded);
                            }
                            numStr = fullNumber;
                        } else {
                            numStr = num.toFixed(0);
                        }
                    }
                }
                phoneStr = numStr;
            }
        } catch (error) {
            logger.warn(`Error converting ${fieldName} scientific notation`, { error, phoneStr });
        }
    }

    // Remove non-digit characters
    let phone = phoneStr.replace(/[^\d]/g, '');

    // Normalize to 233 format
    if (phone && !phone.startsWith('233')) {
        if (phone.length === 9) {
            phone = '233' + phone;
        } else if (phone.length === 10 && phone.startsWith('0')) {
            phone = '233' + phone.substring(1);
        }
    }

    return phone;
};

/**
 * Process a single row of payroll data
 */
const processRow = (values, headerIndexes, rowIndex, t) => {
    const firstName = values[headerIndexes.firstName]?.toString().trim();
    const lastName = values[headerIndexes.lastName]?.toString().trim();
    const position = values[headerIndexes.position]?.toString().trim();
    const amountStr = values[headerIndexes.amount]?.toString().trim().replace(/[^\d.-]/g, '');
    const amount = parseFloat(amountStr);
    const email = values[headerIndexes.email]?.toString().trim();
    const currencyRaw = values[headerIndexes.currency]?.toString().trim();
    const currency = currencyRaw ? currencyRaw.toUpperCase() : '';

    // Handle phone number
    const phoneRaw = values[headerIndexes.phone]?.toString().trim() || '';
    const phone = normalizePhoneNumber(phoneRaw, rowIndex, 'Phone');

    // Check for data loss in phone
    if (phoneRaw && (phoneRaw.includes('E+') || phoneRaw.includes('e+') || phoneRaw.includes('E-') || phoneRaw.includes('e-'))) {
        if (!phone || phone.length !== 12 || !phone.startsWith('233')) {
            throw new Error(`Row ${rowIndex + 2}: Data Loss Detected. The phone number "${phoneRaw}" is truncated in your file. Please use the original Excel (.xlsx) file with the full number, or ensure the cell is formatted as Text.`);
        }
    }

    const paymentChannelRaw = values[headerIndexes.paymentChannel]?.toString().trim() || '';
    let paymentChannel = paymentChannelRaw.toUpperCase().replace(/\s+/g, '_');

    // Convert MOMO to MOBILE_MONEY
    if (paymentChannel === 'MOMO' || paymentChannel === 'MOBILE_MONEY') {
        paymentChannel = 'MOBILE_MONEY';
    }

    // Optional fields
    let network = values[headerIndexes.network]?.toString().trim() || null;
    const mobileNumberRaw = values[headerIndexes.mobileNumber]?.toString().trim() || null;
    const mobileNumber = mobileNumberRaw ? normalizePhoneNumber(mobileNumberRaw, rowIndex, 'Mobile Number') : null;

    // Check for data loss in mobile number
    if (mobileNumberRaw && (mobileNumberRaw.includes('E+') || mobileNumberRaw.includes('e+') || mobileNumberRaw.includes('E-') || mobileNumberRaw.includes('e-'))) {
        if (!mobileNumber || mobileNumber.length !== 12 || !mobileNumber.startsWith('233')) {
            throw new Error(`Row ${rowIndex + 2}: Data Loss Detected. The mobile money number "${mobileNumberRaw}" is truncated in your file. Please use the original Excel (.xlsx) file with the full number, or ensure the cell is formatted as Text.`);
        }
    }

    const bankName = values[headerIndexes.bankName]?.toString().trim() || null;
    const bankAccountNo = values[headerIndexes.bankAccountNo]?.toString().trim() || null;
    const bankBranch = values[headerIndexes.bankBranch]?.toString().trim() || null;

    // Normalize network to uppercase
    if (network) {
        network = network.toUpperCase();
    }

    // Generate reference
    let referenceProvider = 'PAY';
    if (paymentChannel === 'MOBILE_MONEY' && network) {
        referenceProvider = network;
    } else if (paymentChannel === 'BANK') {
        referenceProvider = 'BANK';
    }

    let reference = generateReference(referenceProvider);
    let attempts = 0;
    while (!validateReference(reference) && attempts < 10) {
        reference = generateReference(referenceProvider);
        attempts++;
    }

    if (!validateReference(reference)) {
        throw new Error(`Row ${rowIndex + 2}: Failed to generate valid reference. Generated: ${reference}`);
    }

    // Validation
    if (!firstName || firstName.length === 0) {
        throw new Error(`Row ${rowIndex + 2}: First Name is required`);
    }
    if (!lastName || lastName.length === 0) {
        throw new Error(`Row ${rowIndex + 2}: Last Name is required`);
    }
    if (!position || position.length === 0) {
        throw new Error(`Row ${rowIndex + 2}: Position is required`);
    }
    if (isNaN(amount) || amount <= 0) {
        throw new Error(`Row ${rowIndex + 2}: Valid Amount is required`);
    }
    if (!email || email.length === 0) {
        throw new Error(`Row ${rowIndex + 2}: Email is required`);
    }
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email)) {
        throw new Error(`Row ${rowIndex + 2}: Invalid email format`);
    }
    if (!currency || currency.length === 0) {
        throw new Error(`Row ${rowIndex + 2}: Currency is required`);
    }
    if (!phone || phone.length === 0) {
        throw new Error(`Row ${rowIndex + 2}: Phone is required`);
    }
    if (phone.length < 7) {
        throw new Error(`Row ${rowIndex + 2}: Invalid phone number`);
    }
    if (!paymentChannel || paymentChannel.length === 0) {
        throw new Error(`Row ${rowIndex + 2}: Payment Channel is required`);
    }

    return {
        id: Date.now() + rowIndex,
        firstName,
        lastName,
        position,
        reference,
        amount: Number(amount),
        email,
        currency,
        phone,
        paymentChannel,
        network: network || null,
        mobileNumber: mobileNumber || null,
        bankName: bankName || null,
        bankAccountNo: bankAccountNo || null,
        bankBranch: bankBranch || null,
        name: `${firstName} ${lastName}`,
        salary: `${currency} ${amount.toLocaleString()}`,
        status: 'Active'
    };
};

/**
 * Parse Excel file content into payroll records
 */
export const parseExcelPayroll = (buffer, t) => {
    try {
        const workbook = read(buffer, { type: 'array' });
        const firstSheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[firstSheetName];

        const rows = utils.sheet_to_json(worksheet, { header: 1, raw: true, defval: '' });

        if (rows.length < 2) {
            throw new Error('File must contain at least a header row and one data row');
        }

        const headers = rows[0].map(h => String(h).trim());

        const headerIndexes = {};
        headers.forEach((header, index) => {
            const normalizedHeader = header.toLowerCase().trim();
            if (HEADER_MAP[normalizedHeader]) {
                headerIndexes[HEADER_MAP[normalizedHeader]] = index;
            }
        });

        const requiredFields = ['firstName', 'lastName', 'position', 'amount', 'email', 'currency', 'phone', 'paymentChannel'];
        const missingFields = requiredFields.filter(field => headerIndexes[field] === undefined);

        if (missingFields.length > 0) {
            throw new Error(
                `Missing required columns: ${missingFields.join(', ')}\n` +
                `Found columns: ${headers.join(', ')}`
            );
        }

        const records = [];
        const errors = [];

        rows.slice(1).forEach((row, rowIndex) => {
            if (!row || row.length === 0 || row.every(cell => !cell)) {return;}

            try {
                const record = processRow(row, headerIndexes, rowIndex, t);
                records.push(record);
            } catch (error) {
                errors.push({ row: rowIndex + 2, error: error.message });
            }
        });

        if (errors.length > 0) {
            const errorMsg = `Errors in ${errors.length} row(s): ${errors.slice(0, 3).map(e => e.error).join('; ')}`;
            throw new Error(errorMsg);
        }

        return records;
    } catch (error) {
        logger.error('Error parsing Excel payroll file', { error });
        throw error;
    }
};

/**
 * Parse CSV file content into payroll records
 */
export const parseCSVPayroll = (text, t) => {
    const textWithoutBOM = text.charCodeAt(0) === 0xFEFF ? text.slice(1) : text;
    const lines = textWithoutBOM.split(/\r?\n/).filter(line => line.trim());

    if (lines.length < 2) {
        throw new Error('File must contain at least a header row and one data row');
    }

    // Parse header row
    const headerLine = lines[0];
    const headerValues = [];
    let current = '';
    let inQuotes = false;

    for (let i = 0; i < headerLine.length; i++) {
        const char = headerLine[i];
        if (char === '"') {
            inQuotes = !inQuotes;
        } else if (char === ',' && !inQuotes) {
            headerValues.push(current.trim().replace(/^"|"$/g, ''));
            current = '';
        } else {
            current += char;
        }
    }
    headerValues.push(current.trim().replace(/^"|"$/g, ''));

    const headers = headerValues.map(h => h.trim().replace(/"/g, ''));

    const headerIndexes = {};
    headers.forEach((header, index) => {
        const normalizedHeader = header.toLowerCase().trim();
        if (HEADER_MAP[normalizedHeader]) {
            headerIndexes[HEADER_MAP[normalizedHeader]] = index;
        }
    });

    const requiredFields = ['firstName', 'lastName', 'position', 'amount', 'email', 'currency', 'phone', 'paymentChannel'];
    const missingFields = requiredFields.filter(field => headerIndexes[field] === undefined);

    if (missingFields.length > 0) {
        throw new Error(
            `Missing required columns: ${missingFields.join(', ')}\n` +
            `Found columns: ${headers.join(', ')}`
        );
    }

    const records = [];
    const errors = [];

    lines.slice(1).forEach((line, rowIndex) => {
        if (!line.trim()) {return;}

        const values = [];
        current = '';
        inQuotes = false;

        for (let i = 0; i < line.length; i++) {
            const char = line[i];
            if (char === '"') {
                inQuotes = !inQuotes;
            } else if (char === ',' && !inQuotes) {
                values.push(current.trim());
                current = '';
            } else {
                current += char;
            }
        }
        values.push(current.trim());

        try {
            const record = processRow(values, headerIndexes, rowIndex, t);
            records.push(record);
        } catch (error) {
            errors.push({ row: rowIndex + 2, error: error.message });
        }
    });

    if (errors.length > 0) {
        const errorMsg = `Errors in ${errors.length} row(s): ${errors.slice(0, 3).map(e => e.error).join('; ')}`;
        throw new Error(errorMsg);
    }

    return records;
};
